#include <bits/stdc++.h>
using namespace std;
int m[200],len,n;
bool check(){
    for(int i=0;i<len/2;i++)if(m[i]!=m[len-i-1])return false;
    return true;
}
void pls(){
    int tmp[200];
    for(int i=0;i<len;i++)tmp[i]=m[len-i-1];
    for(int i=0;i<len;i++){
        m[i]+=tmp[i];
        m[i+1]+=m[i]/n;
        m[i]%=n;
    }
    if(m[len])len++;
}
int main(){
    string s;
    cin>>n>>s;
    len=s.size();
    for(int i=0;i<s.size();i++){
        if(n<16)m[i]=s[s.size()-i-1]-'0';
        else{
            if(s[s.size()-i-1]>='A' && s[s.size()-i-1]<='Z')
                m[i]=s[s.size()-i-1]-'A'+10;
            else m[i]=s[s.size()-i-1]-'0';
        }
    }
    if(check()){
        cout<<"STEP=0";
        return 0;
    }
    for(int i=1;i<=30;i++){
        pls();
        if(check()){
            cout<<"STEP="<<i;
            return 0;
        }
    }
    cout<<"Impossible!";
    return 0;
}
